/**
 * TLog SDK v1.1 — TALON 組み込み用（旧API互換）
 */
(function(global) {
  'use strict';

  let _config = {};
  let _traceId = null;
  let _seq = 0;

  function post(path, body) {
    return fetch(_config.serverUrl + path, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'x-api-key': _config.apiKey,
      },
      body: JSON.stringify(body),
    }).catch(function(e) {
      console.warn('[TLog] 送信失敗:', e.message);
    });
  }

  const TLog = {
    // ─── 新API ───
    init: function(config) {
      _config = Object.assign({
        serverUrl: 'http://192.168.1.11:3099',
        projectId: 'legacy',
      }, config);
      console.log('[TLog] 初期化完了 project=' + _config.projectId);
    },

    startTrace: function(opts) {
      opts = opts || {};
      return post('/sdk/trace/start', {
        projectId: _config.projectId,
        operatorId: opts.userId || 'unknown',
        metadata:   opts.meta  || {},
        label:      opts.label || '',
      }).then(function(res) {
        if (!res) return;
        return res.json().then(function(data) {
          _traceId = data.traceId;
          _seq = 0;
          console.log('[TLog] Trace開始:', _traceId);
        });
      });
    },

    stopTrace: function() {
      if (!_traceId) return Promise.resolve();
      return post('/sdk/trace/stop', {
        traceId:   _traceId,
        projectId: _config.projectId,
      }).then(function() {
        console.log('[TLog] Trace終了:', _traceId);
        _traceId = null;
      });
    },

    log: function(eventType, screenName, elementId, payload) {
      if (!_traceId) return;
      _seq++;
      return post('/sdk/log', {
        traceId:    _traceId,
        projectId:  _config.projectId,
        eventType:  eventType  || 'ACTION',
        screenName: screenName || '',
        elementId:  elementId  || '',
        seqNo:      _seq,
        payload:    payload    || {},
      });
    },

    getTraceId: function() { return _traceId; },

    // ─── 旧API互換（TALON既存コードをそのまま動かすためのシム）───
    screenLoad: function(screenId, screenName) {
      console.log('[TLog] screenLoad:', screenId, screenName);
      if (!_traceId) return;
      return TLog.log('SCREEN_LOAD', screenId, '', { label: screenName });
    },

    bootstrap: function(opts) {
      console.log('[TLog] bootstrap:', opts);
      // 旧APIの初期化処理 → 新APIでは init() 済みのため何もしない
    },

    screenCapture: function(screenId, label) {
      console.log('[TLog] screenCapture:', screenId);
      if (!_traceId) return;
      return TLog.log('SCREENSHOT', screenId, '', { label: label || '' });
    },

    action: function(screenId, elementId, payload) {
      if (!_traceId) return;
      return TLog.log('ACTION', screenId, elementId, payload || {});
    },
  };

  global.TLog = TLog;
})(window);
